// TestGetMarketVolume tests that the total volume of trades is returned correctly
func TestGetMarketVolume(t *testing.T) {
	tests := []struct {
		Name           string
		Bets           []models.Bet
		ExpectedVolume int64
	}{
		{
			Name:           "empty slice",
			Bets:           []models.Bet{},
			ExpectedVolume: 0,
		},
		{
			Name: "positive Bets",
			Bets: []models.Bet{
				{Amount: 100},
				{Amount: 200},
				{Amount: 300},
			},
			ExpectedVolume: 600,
