				makeDBPMBet(1, "NO", "two", 1),
			},
			wantYes: 1,
			wantNo:  0,
		},
		{
			name: "Net NO after mix",

			name: "Net NO after mix",
			bets: []models.Bet{
				makeDBPMBet(1, "YES", "one", 0),
				makeDBPMBet(2, "NO", "two", 1),
			},
			wantYes: 0,
			wantNo:  1,
		},
		{
			name:    "No bets",
			bets:    []models.Bet{},
			wantYes: 0,
			wantNo:  0,
		},
		{
			name: "Ambiguous (net 0)",
			bets: []models.Bet{
				makeDBPMBet(1, "YES", "one", 0),
				makeDBPMBet(1, "NO", "two", 1),
			},
			wantYes: 0,
			wantNo:  0,
		},
	}

	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
